   767→// CreateSemanticRelease inserts a semantic release and its source release links
   768→// in a single transaction. The sr.ID field is populated on success.
   769→func (s *PgStore) CreateSemanticRelease(ctx context.Context, sr *models.SemanticRelease, releaseIDs []string) error {
   770→	tx, err := s.pool.Begin(ctx)
   771→	if err != nil {
   772→		return fmt.Errorf("begin tx: %w", err)
   773→	}
   774→	defer tx.Rollback(ctx)
   775→
   776→	err = tx.QueryRow(ctx,
   777→		`INSERT INTO semantic_releases (project_id, version, report, status, completed_at)
   778→		 VALUES ($1, $2, $3, $4, $5)
   779→		 RETURNING id, created_at`,
   780→		sr.ProjectID, sr.Version, sr.Report, sr.Status, sr.CompletedAt,
   781→	).Scan(&sr.ID, &sr.CreatedAt)
   782→	if err != nil {
   783→		return fmt.Errorf("insert semantic release: %w", err)
   784→	}
   785→
   786→	for _, relID := range releaseIDs {
   787→		_, err = tx.Exec(ctx,
   788→			`INSERT INTO semantic_release_sources (semantic_release_id, release_id)
   789→			 VALUES ($1, $2) ON CONFLICT DO NOTHING`,
   790→			sr.ID, relID,
   791→		)
   792→		if err != nil {
   793→			return fmt.Errorf("insert semantic release source: %w", err)
   794→		}
   795→	}
   796→
   797→	return tx.Commit(ctx)
   798→}
