   890→func (s *PgStore) GetTrend(ctx context.Context, granularity string, start, end time.Time) ([]TrendBucket, error) {
   891→	// Validate granularity to one of three literal values (no injection risk).
   892→	var trunc string
   893→	switch granularity {
   894→	case "daily":
   895→		trunc = "day"
   896→	case "weekly":
   897→		trunc = "week"
   898→	case "monthly":
   899→		trunc = "month"
   900→	default:
   901→		return nil, fmt.Errorf("invalid granularity: %s", granularity)
   902→	}
   903→
   904→	query := fmt.Sprintf(`
   905→		WITH buckets AS (
   906→			SELECT date_trunc('%s', gs)::date AS period
   907→			FROM generate_series($1::timestamptz, $2::timestamptz, '1 %s'::interval) gs
   908→		)
   909→		SELECT
   910→			b.period,
   911→			COALESCE(r.cnt, 0) AS releases,
   912→			COALESCE(sr.cnt, 0) AS semantic_releases
   913→		FROM buckets b
   914→		LEFT JOIN (
   915→			SELECT date_trunc('%s', COALESCE(released_at, created_at))::date AS period,
   916→			       COUNT(*) AS cnt
   917→			FROM releases
   918→			WHERE COALESCE(released_at, created_at) >= $1 AND COALESCE(released_at, created_at) < $2
   919→			GROUP BY 1
   920→		) r ON r.period = b.period
   921→		LEFT JOIN (
   922→			SELECT date_trunc('%s', created_at)::date AS period,
   923→			       COUNT(*) AS cnt
   924→			FROM semantic_releases
   925→			WHERE created_at >= $1 AND created_at < $2
   926→			GROUP BY 1
   927→		) sr ON sr.period = b.period
   928→		ORDER BY b.period
   929→	`, trunc, trunc, trunc, trunc)
   930→
   931→	rows, err := s.pool.Query(ctx, query, start, end)
   932→	if err != nil {
   933→		return nil, fmt.Errorf("get trend: %w", err)
   934→	}
   935→	defer rows.Close()
   936→
   937→	var buckets []TrendBucket
   938→	for rows.Next() {
   939→		var b TrendBucket
   940→		var period time.Time
   941→		if err := rows.Scan(&period, &b.Releases, &b.SemanticReleases); err != nil {
   942→			return nil, fmt.Errorf("scan trend bucket: %w", err)
   943→		}
   944→		b.Period = period.Format("2006-01-02")
   945→		buckets = append(buckets, b)
   946→	}
   947→	if buckets == nil {
   948→		buckets = []TrendBucket{}
   949→	}
   950→	return buckets, nil
   951→}
