    32→// List handles GET /channels — returns a paginated list of notification channels.
    33→func (h *ChannelsHandler) List(w http.ResponseWriter, r *http.Request) {
    34→	page, perPage := ParsePagination(r)
    35→	channels, total, err := h.store.ListChannels(r.Context(), page, perPage)
    36→	if err != nil {
    37→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list channels")
    38→		return
    39→	}
    40→	if channels == nil {
    41→		channels = []models.NotificationChannel{}
    42→	}
    43→	RespondList(w, r, http.StatusOK, channels, page, perPage, total)
    44→}
