    46→// Create handles POST /channels — creates a new notification channel.
    47→func (h *ChannelsHandler) Create(w http.ResponseWriter, r *http.Request) {
    48→	var ch models.NotificationChannel
    49→	if err := DecodeJSON(r, &ch); err != nil {
    50→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
    51→		return
    52→	}
    53→	ch.Type = strings.TrimSpace(ch.Type)
    54→	ch.Name = strings.TrimSpace(ch.Name)
    55→	if ch.Type == "" {
    56→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "type is required")
    57→		return
    58→	}
    59→	if ch.Name == "" {
    60→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "name is required")
    61→		return
    62→	}
    63→	if ch.Config == nil || string(ch.Config) == "null" {
    64→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "config is required")
    65→		return
    66→	}
    67→	if err := h.store.CreateChannel(r.Context(), &ch); err != nil {
    68→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to create channel")
    69→		return
    70→	}
    71→	RespondJSON(w, r, http.StatusCreated, ch)
    72→}
    73→
    74→// Get handles GET /channels/{id} — returns a single notification channel.
    75→func (h *ChannelsHandler) Get(w http.ResponseWriter, r *http.Request) {
    76→	id := r.PathValue("id")
    77→	if id == "" {
    78→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid channel ID")
    79→		return
    80→	}
    81→	ch, err := h.store.GetChannel(r.Context(), id)
    82→	if err != nil {
    83→		RespondError(w, r, http.StatusNotFound, "not_found", "Channel not found")
    84→		return
    85→	}
    86→	RespondJSON(w, r, http.StatusOK, ch)
    87→}
    88→
    89→// Update handles PUT /channels/{id} — updates an existing notification channel.
    90→func (h *ChannelsHandler) Update(w http.ResponseWriter, r *http.Request) {
    91→	id := r.PathValue("id")
    92→	if id == "" {
    93→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid channel ID")
    94→		return
    95→	}
    96→	var ch models.NotificationChannel
    97→	if err := DecodeJSON(r, &ch); err != nil {
    98→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
    99→		return
   100→	}
   101→	ch.Type = strings.TrimSpace(ch.Type)
   102→	ch.Name = strings.TrimSpace(ch.Name)
   103→	if ch.Type == "" {
   104→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "type is required")
   105→		return
   106→	}
   107→	if ch.Name == "" {
   108→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "name is required")
   109→		return
   110→	}
   111→	if ch.Config == nil || string(ch.Config) == "null" {
   112→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "config is required")
   113→		return
   114→	}
   115→	if err := h.store.UpdateChannel(r.Context(), id, &ch); err != nil {
   116→		RespondError(w, r, http.StatusNotFound, "not_found", "Channel not found")
   117→		return
   118→	}
   119→	ch.ID = id
   120→	RespondJSON(w, r, http.StatusOK, ch)
   121→}
   122→
   123→// Delete handles DELETE /channels/{id} — deletes a notification channel.
   124→func (h *ChannelsHandler) Delete(w http.ResponseWriter, r *http.Request) {
   125→	id := r.PathValue("id")
   126→	if id == "" {
