    22→export function SubscriptionForm({ initial, onSubmit, title, onSuccess, onCancel }: SubscriptionFormProps) {
    23→  const router = useRouter();
    24→  const [saving, setSaving] = useState(false);
    25→  const [error, setError] = useState("");
    26→  const [type, setType] = useState<"source" | "project">(initial?.type ?? "project");
    27→  const [channelId, setChannelId] = useState(initial?.channel_id ?? "");
    28→  const [projectId, setProjectId] = useState(initial?.project_id ?? "");
    29→  const [sourceId, setSourceId] = useState(initial?.source_id ?? "");
    30→  const [versionFilter, setVersionFilter] = useState(initial?.version_filter ?? "");
    31→
    32→  const { data: projectsData } = useSWR("projects-for-sub", () => projectsApi.list());
    33→  const { data: channelsData } = useSWR("channels-for-sub", () => channelsApi.list());
    34→  const { data: sourcesData } = useSWR(
    35→    type === "source" && projectId ? `sources-for-sub-${projectId}` : null,
    36→    () => sourcesApi.listByProject(projectId)
    37→  );
    38→
    39→  const handleSubmit = async (e: React.FormEvent) => {
    40→    e.preventDefault();
    41→    setError("");
    42→    setSaving(true);
    43→    try {
    44→      await onSubmit({
    45→        channel_id: channelId,
    46→        type,
    47→        source_id: type === "source" ? sourceId : undefined,
    48→        project_id: type === "project" ? projectId : undefined,
    49→        version_filter: versionFilter || undefined,
    50→      });
    51→      if (onSuccess) {
    52→        onSuccess();
    53→      } else {
    54→        router.push("/subscriptions");
    55→      }
    56→    } catch (err: unknown) {
    57→      setError(err instanceof Error ? err.message : "Failed to save");
    58→    } finally {
    59→      setSaving(false);
    60→    }
    61→  };
    62→
    63→  const formContent = (
    64→    <form onSubmit={handleSubmit} className="space-y-4">
    65→      {error && <div className="rounded-md bg-red-50 p-3 text-sm text-red-700">{error}</div>}
    66→      <div className="space-y-2">
    67→        <Label>Subscription Type</Label>
    68→        <Select value={type} onValueChange={(v) => setType(v as "source" | "project")}>
    69→          <SelectTrigger><SelectValue /></SelectTrigger>
    70→          <SelectContent>
    71→            <SelectItem value="project">Project</SelectItem>
    72→            <SelectItem value="source">Source</SelectItem>
    73→          </SelectContent>
    74→        </Select>
    75→      </div>
    76→      {type === "project" && (
    77→        <div className="space-y-2">
    78→          <Label>Project</Label>
    79→          <Select value={projectId} onValueChange={setProjectId} required>
