    e.preventDefault();
    setError("");
    setSaving(true);
    try {
      if (isEditing) {
        await onSubmit({
          channel_id: channelId,
          type,
          source_id: type === "source" ? sourceId : undefined,
          project_id: type === "project" ? projectId : undefined,
          version_filter: versionFilter || undefined,
