   722→	err := s.pool.QueryRow(ctx,
   723→		`SELECT id, source_id, version, COALESCE(raw_data,'{}'), released_at, created_at
   724→		 FROM releases
   725→		 WHERE source_id = $1 AND version != $2
   726→		 ORDER BY COALESCE(released_at, created_at) DESC
   727→		 LIMIT 1`, sourceID, beforeVersion,
   728→	).Scan(&rel.ID, &rel.SourceID, &rel.Version, &rel.RawData, &rel.ReleasedAt, &rel.CreatedAt)
   729→	if err != nil {
   730→		if err.Error() == "no rows in result set" {
   731→			return nil, nil
   732→		}
   733→		return nil, fmt.Errorf("get previous release: %w", err)
   734→	}
   735→	return &rel, nil
   736→}
