   773→// UpdateAgentRunStatus sets the status of an agent run and updates the
   774→// started_at timestamp when transitioning to "running".
   775→func (s *PgStore) UpdateAgentRunStatus(ctx context.Context, id, status string) error {
   776→	var query string
   777→	switch status {
   778→	case "running":
   779→		query = `UPDATE agent_runs SET status = $1, started_at = NOW() WHERE id = $2`
   780→	case "completed":
   781→		query = `UPDATE agent_runs SET status = $1, completed_at = NOW() WHERE id = $2`
   782→	default:
   783→		query = `UPDATE agent_runs SET status = $1 WHERE id = $2`
   784→	}
   785→	tag, err := s.pool.Exec(ctx, query, status, id)
   786→	if err != nil {
   787→		return fmt.Errorf("update agent run status: %w", err)
   788→	}
   789→	if tag.RowsAffected() == 0 {
   790→		return fmt.Errorf("agent run not found: %s", id)
   791→	}
   792→	return nil
   793→}
